import React, { useMemo, useState } from "react";
import { OverlayScrollbarsComponent } from "overlayscrollbars-react";
import { closeSection, getDateFormat } from "./../helper/helpers";

import PortfolioGrid from "./inc/PortfolioGrid";
import SimpleSlider from "./inc/SimpleSlider";
import ClientSlider from "./inc/ClientSlider";

const Portfolio = ({ data, api }) => {

    const [activeCategory, setActiveCategory] = useState("all");

  const getCatClass = (title = "") =>
    title.toLowerCase().replace(/\s+/g, ""); 
  const filteredPortfolio = useMemo(() => {
    if (activeCategory === "all") return data?.portfolioes || [];

    return (data?.portfolioes || []).filter(
      item =>
        getCatClass(item.category?.title) === activeCategory
    );
  }, [activeCategory, data]);

  return (
    <OverlayScrollbarsComponent
      options={{ scrollbars: { autoHide: "scroll" } }}
      className="portfolio section-panel"
      id="portfolio"
    >
      <button
        className="panel-close-btn"
        onClick={() => closeSection("portfolio")}
      >
        <i className="fa-light fa-xmark"></i>
      </button>

      <div className="portfolio-content">
        <div className="container">

          <h2 className="section-title title-center">
            Take a look on <span>my past</span>
          </h2>

           {/* ================= FILTER NAV ================= */}
        <div className="filter-nav">
          <button
            className={`filter-btn ${
              activeCategory === "all" ? "active" : ""
            }`}
            onClick={() => setActiveCategory("all")}
          >
            Show All
          </button>

          {data?.portfolio_cats?.map(cat => {
            const catClass = getCatClass(cat.title);
            return (
              <button
                key={cat.id}
                className={`filter-btn ${
                  activeCategory === catClass ? "active" : ""
                }`}
                onClick={() => setActiveCategory(catClass)}
              >
                {cat.title}
              </button>
            );
          })}
        </div>

        {/* ================= PORTFOLIO GRID ================= */}
        <div className="portfolio-row">
          {filteredPortfolio.length > 0 ? (
            filteredPortfolio.map((portfolio, i) => (
              <PortfolioGrid
                key={portfolio.id || i}
                cat_class={getCatClass(portfolio.category?.title)}
                cat_name={portfolio.category?.title}
                photo={
                  portfolio.photo
                    ? `${api}/${portfolio.photo}`
                    : "https://via.placeholder.com/420x260"
                }
                title={portfolio.title}
                start_date={getDateFormat(portfolio.start_date)}
                end_date={getDateFormat(portfolio.end_date)}
                rating={portfolio.rating || 0}
                url={portfolio.url || ""}
              />
            ))
          ) : (
            <h3 className="empty-msg">
              Nothing to show in this category 😞
            </h3>
          )}
        </div>

        </div>
      </div>

      <div className="our-client">
        <div className="container">
          <ClientSlider
            api={api}
            clients={data?.clients || []}
          />
        </div>
      </div>

      <div className="testimonial">
        <div className="container">
          <h2 className="section-title title-center">
            Clients Says About <span>me</span>
          </h2>

          <SimpleSlider
            api={api}
            testimonials={data?.testimonials || []}
          />
        </div>
      </div>
    </OverlayScrollbarsComponent>
  );
};

export default Portfolio;
