import React, { useRef, useEffect } from "react";
import { OverlayScrollbarsComponent } from "overlayscrollbars-react";
import { closeSection } from "./../helper/helpers";

import  BlogGridItem from './inc/BlogGridItem'

const Blog = ({ data, author, api }) => {


  return (
    <OverlayScrollbarsComponent
      options={{ scrollbars: { autoHide: "scroll" } }}
      className="blog section-panel"
      id="blog"
    >
      <button className="panel-close-btn" onClick={() => closeSection("blog")}>
        <i className="fa-light fa-xmark"></i>
      </button>
      <div className="blog-content">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-12">
              <h2 className="section-title title-center">
                my latest <span>article</span> collection
              </h2>
            </div>
          </div>
          <div className="row g-4 justify-content-center">
          {
                (data) ? Object.values(data).map((blog_item, ci) => (
                  <BlogGridItem key={ci} post={blog_item} thumb={blog_item.image} post_title={blog_item.title}  post_date={blog_item.date} post_author={ (author) ? author.site_name : 'Sazzad' } />
                  
                ) ) : ''
              }

          
            <div className="col-12">
              <div className="subscribe-wrap">
                <div className="subscribe">
                  <h3>subscribe my newsletter</h3>
                  <form >
                    <input
                      type="email"
                      placeholder="Enter your email address..."
                    />
                    <button onClick={ () => function() { return false } } className="def-btn">Subscribe</button>
                  </form>
                </div>
              </div>
            </div>

            
          </div>
        </div>
      </div>
    </OverlayScrollbarsComponent>
  );
};

export default Blog;
