import React from "react";
import { OverlayScrollbarsComponent } from "overlayscrollbars-react";
import { closeSection, openSection } from "./../helper/helpers";
import Services from "./inc/Services";  


const Service = ({data, api}) => {
  const opencontact = () => {   
    closeSection("service")
    openSection("contact")   
  }
  return (
 
    <OverlayScrollbarsComponent
      className="service section-panel"
      options={{ scrollbars: { autoHide: "scroll" } }}
      id="service"
    >
      <button
        className="panel-close-btn"
        onClick={() => closeSection("service")}
      >
        <i className="fa-light fa-xmark"></i>
      </button>

      <div className="service-content">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-xl-6 col-lg-5">
              <h2 className="section-title title-center">
                <span>My</span> Services
              </h2>
            </div>
          </div>
          <div className="row g-md-4 g-sm-3 g-4 justify-content-between">
          <Services services={data.services} />
          
          </div>
        </div>
      </div>
      <div className="cta mb-3">
        <div className="container">
          <div className="d-sm-flex d-block align-items-center">
            <div className="part-txt">
              <h2>Have Any Project In Mind?</h2>
            </div>
            <div className="part-btn">
              <a onClick={() => opencontact()  } className="def-btn def-btn-2">
                Submit A Proposal
              </a>
            </div>
          </div>
        </div>
      </div>
      
    </OverlayScrollbarsComponent>
  );
};

export default Service;
