
import React, { useState, useRef, useEffect } from 'react'
import Loader from './components/Loader';
import Header from './components/Header';
import Banner from './components/Banner';
import About from './components/About';
import Service from './components/Service';
import Portfolio from './components/Portfolio';
import Contact from './components/Contact';

import Faq from './components/Faq';
import Gallery from './components/Gallery';
import Blog from './components/Blog';
import BlogDetailModal from './components/inc/BlogDetailModal';
// import  {showModal} from  './helper/helpers'

import myData from './data.json';


// import './App.css';

function App() {


  const lightRef = useRef()
  const [lightBox, setLightBox] = useState('')
  const [lightBoxImg, setLightBoxImg] = useState('')
  const [isLoading, setIsLoading] = useState(false);

  const showLightBox = (img_scource) => {
    setLightBoxImg(img_scource)
    lightRef.src = img_scource;
    setLightBox('active')
  }

  const lightBoxClose = () => {
    setLightBox('')
  }

  const [homedata, setHomedata] = useState()
  const [apiRoot, setApiRoot] = useState()


  useEffect(() => {

    setHomedata(myData);
    setApiRoot(myData.common.api_storage_url);
    setIsLoading(true);

  }, [setHomedata]); // Ensure all dependencies used in the effect are declared.



  return (

    <div className="App2">

      <div className="content-wrap">
        <Loader isLoading={isLoading} />
        <Header data={homedata ? homedata.common : {}} api={apiRoot} />

        <Banner data={homedata ? homedata.banner : {}} api={apiRoot} />
        <About data={homedata ? homedata.about : {}} api={apiRoot} />
        <Service data={homedata ? homedata.service : {}} api={apiRoot} />
        <Portfolio data={homedata ? homedata.portfolio : {}} api={apiRoot} />
        <Contact data={homedata ? homedata.contact : {}} api={apiRoot} />

        <Faq data={homedata ? homedata.faq : {}} />
        <Gallery showLightBox={showLightBox} data={homedata ? homedata.gallery : {}} api={apiRoot} />
        <Blog data={homedata ? homedata.blog : {}} api={apiRoot} author={homedata ? homedata.common : {}} />

      </div>
      <BlogDetailModal />
      <div onClick={lightBoxClose} className={`image-lightbox-panel ${lightBox}`}>
        <img src={`${lightBoxImg}?size=300x300`} ref={lightRef} className="lightbox-image" alt="my portfolio" />

      </div>
    </div>
  );
}

export default App;
