import React, { useEffect, useState } from "react";
import Slider from "react-slick";
import TestimonialItem from "./TestimonialItem";

const SimpleSlider = ({ testimonials, api }) => {
  const [sliderKey, setSliderKey] = useState(0);

  // 🔥 Force re-render when data loads
  useEffect(() => {
    if (testimonials && Object.keys(testimonials).length > 0) {
      setSliderKey(prev => prev + 1);
    }
  }, [testimonials]);

  const ArrowPrev = ({ onClick }) => (
    <button className="slick-arrow slick-prev" onClick={onClick}>
      <i className="fa-regular fa-left-long"></i>
    </button>
  );

  const ArrowNext = ({ onClick }) => (
    <button className="slick-arrow slick-next" onClick={onClick}>
      <i className="fa-regular fa-right-long"></i>
    </button>
  );

  const settings = {
    dots: false,
    infinite: true,
    speed: 500,
    slidesToShow: 1,
    slidesToScroll: 1,
    arrows: true,
    nextArrow: <ArrowNext />,
    prevArrow: <ArrowPrev />,
    adaptiveHeight: true
  };

  if (!testimonials || Object.keys(testimonials).length === 0) {
    return null;
  }

  return (
    <Slider
      key={sliderKey}   
      {...settings}
      className="testimonial-slider"
    >
      {Object.values(testimonials).map((slide, i) => (
        <div key={i} className="single-feedback">
          <TestimonialItem
            api={api}
            photo={slide.photo}
            name={slide.name}
            designation={slide.position}
            description={slide.message}
          />
        </div>
      ))}
    </Slider>
  );
};

export default SimpleSlider;
